### 3. main() の整理後イメージ

```go
func main() {
    // --- フラグ解析 ---
    noBanner  := flag.Bool("no-banner", false, "suppress Notification Center banner")
    noSound   := flag.Bool("no-sound",  false, "suppress sound")
    soundFile := flag.String("sound", "/System/Library/Sounds/Glass.aiff", "path to sound file played on completion")
    flag.Usage = func() { /* ... */ }
    flag.Parse()

    args := flag.Args()
    if len(args) == 0 {
        flag.Usage()
        os.Exit(1)
    }

    agentName := agentDisplayName(args[0])

    // --- PTY 起動 ---
    cmd  := exec.Command(args[0], args[1:]...)
    ptmx, err := pty.Start(cmd)
    if err != nil {
        fmt.Fprintf(os.Stderr, "crai: failed to start PTY: %v\n", err)
        os.Exit(1)
    }
    defer ptmx.Close()

    // --- ターミナルリサイズ対応 ---
    sigCh := make(chan os.Signal, 1)
    signal.Notify(sigCh, syscall.SIGWINCH)
    go func() {
        for range sigCh {
            pty.InheritSize(os.Stdin, ptmx)
        }
    }()
    sigCh <- syscall.SIGWINCH

    // --- raw モード ---
    oldState, err := term.MakeRaw(int(os.Stdin.Fd()))
    if err != nil {
        fmt.Fprintf(os.Stderr, "crai: failed to set raw mode: %v\n", err)
        os.Exit(1)
    }
    defer term.Restore(int(os.Stdin.Fd()), oldState)

    // --- goroutine 起動 ---
    mon := &monitor{lastOutput: time.Now()}
    go mon.watchAndNotify(agentName, *soundFile, *noSound, *noBanner)
    go mon.copyPTYToStdout(ptmx)
    go mon.copyStdinToPTY(ptmx)

    cmd.Wait()
}
```

`main()` の最後5行が「3本のgoroutineを起動して待機する」だけになり、何が並走しているかが一覧できます。

